import { CreateTask, UpdateTask } from 'wasp/server/actions'

type CreateTaskArgs = {
  description: string
}

export const createTask: CreateTask<CreateTaskArgs, any> = async (args, context) => {
  if (!context.user) {
    throw new Error('Not authorized')
  }
  return context.entities.Task.create({
    data: {
      description: args.description,
      user: { connect: { id: context.user.id } }
    }
  })
}

type UpdateTaskArgs = {
  id: number,
  isDone: boolean
}

export const updateTask: UpdateTask<UpdateTaskArgs, any> = async (args, context) => {
  if (!context.user) {
    throw new Error('Not authorized')
  }
  return context.entities.Task.updateMany({
    where: {
      id: args.id,
      userId: context.user.id
    },
    data: {
      isDone: args.isDone
    }
  })
}

