import React, { useState } from 'react'
import { useQuery, useAction, getTasks, createTask, updateTask } from 'wasp/client/operations'
import { logout } from 'wasp/client/auth'

export const MainPage = () => {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskFn = useAction(createTask)
  const updateTaskFn = useAction(updateTask)

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + error

  return (
    <div className="container">
      <main>
        <h1 className="title">Todo List</h1>
        <NewTaskForm createTask={createTaskFn} />
        <br />
        {tasks && tasks.length > 0 ? (
          <TasksList tasks={tasks} updateTask={updateTaskFn} />
        ) : (
          'No tasks yet.'
        )}
        <br />
        <button onClick={logout}>Logout</button>
      </main>
    </div>
  )
}

const NewTaskForm = ({ createTask }: { createTask: any }) => {
  const [description, setDescription] = useState('')

  const handleSubmit = async (event: any) => {
    event.preventDefault()
    if (!description.trim()) return
    try {
      await createTask({ description })
      setDescription('')
    } catch (err: any) {
      window.alert('Error: ' + err.message)
    }
  }

  return (
    <form onSubmit={handleSubmit}>
      <input
        type="text"
        value={description}
        onChange={(e) => setDescription(e.target.value)}
        placeholder="Enter task description"
      />
      <button type="submit">Add Task</button>
    </form>
  )
}

const TasksList = ({ tasks, updateTask }: { tasks: any[], updateTask: any }) => {
  return (
    <ul style={{ listStyleType: 'none', padding: 0 }}>
      {tasks.map((task) => (
        <li key={task.id} style={{ marginBottom: '8px' }}>
          <label style={{ display: 'flex', alignItems: 'center', cursor: 'pointer' }}>
            <input
              type="checkbox"
              checked={task.isDone}
              onChange={async (e) => {
                try {
                  await updateTask({ id: task.id, isDone: e.target.checked })
                } catch (err: any) {
                  window.alert('Error: ' + err.message)
                }
              }}
              style={{ marginRight: '10px' }}
            />
            <span style={{ textDecoration: task.isDone ? 'line-through' : 'none' }}>
              {task.description}
            </span>
          </label>
        </li>
      ))}
    </ul>
  )
}

